            return def;
        }
    }
    // Second: is there an MV whose `to` points at this table?
    for (const def of definitions) {
        if (def.kind === 'materialized_view' &&
            def.to.database === database &&
            def.to.name === table) {
            // Find a source table in the same database as the MV
            for (const sourceDef of definitions) {
                if (sourceDef.kind === 'table' && sourceDef.database === def.database) {
                    return sourceDef;
                }
            }
        }
    }
    return undefined;
